169: 	m.initObjectSelector.Do(func() {
170: 		m.objectSelector, m.objectSelectorErr = metav1.LabelSelectorAsSelector(m.ObjectSelector)
171: 	})
172: 	return m.objectSelector, m.objectSelectorErr
173: }
