284: 				HasParams:     false,
285: 				HasAuthorizer: true,
286: 				StrictCost:    strictCost,
287: 			},
288: 			environment.StoredExpressions,
289: 		), v.FailurePolicy, "webhook", "validating", v.Name)
290: 	})
291: 	return v.compiledMatcher
292: }
